div.script:
document.addEventListener("DOMContentLoaded", function() {
    // ---- OTP Input Auto-Focus ----
    const inputs = document.querySelectorAll('#otpInputGroup input');
    inputs.forEach((input, index) => {
        input.addEventListener('input', function(e) {
            this.value = this.value.replace(/[^0-9]/g, '');
            if (this.value.length === 1 && index < inputs.length - 1) {
                inputs[index + 1].focus();
            }
        });
        input.addEventListener('keydown', function(e) {
            if (e.key === 'Backspace' && this.value === '' && index > 0) {
                inputs[index - 1].focus();
                inputs[index - 1].value = '';
            }
        });
        input.addEventListener('paste', function(e) {
            e.preventDefault();
            const data = (e.clipboardData || window.clipboardData).getData('text').replace(/[^0-9]/g, '');
            for (let i = 0; i < Math.min(data.length, inputs.length); i++) {
                inputs[i].value = data[i];
            }
            const focusIdx = Math.min(data.length, inputs.length - 1);
            inputs[focusIdx].focus();
        });
        input.addEventListener('focus', function() { this.style.borderColor = '#171717'; });
        input.addEventListener('blur', function() { this.style.borderColor = '#d4d4d4'; });
    });

    // ---- Countdown Timer ----
    let totalSeconds = 5 * 60;
    const timerEl = document.getElementById('otpTimer');
    const resendBtn = document.getElementById('resendBtn');
    const otpForm = document.getElementById('otpForm');
    const verifyBtn = document.getElementById('verifyBtn');

    if (otpForm && verifyBtn) {
        otpForm.addEventListener('submit', function(e) {
            if (verifyBtn.disabled) {
                e.preventDefault();
                return;
            }
            verifyBtn.disabled = true;
            verifyBtn.textContent = 'Memproses...';
        });
    }

    function updateTimer() {
        const min = Math.floor(totalSeconds / 60).toString().padStart(2, '0');
        const sec = (totalSeconds % 60).toString().padStart(2, '0');
        if (timerEl) timerEl.textContent = `kode berakhir ${min}:${sec}`;
        if (totalSeconds <= 0) {
            clearInterval(timerInterval);
            if (timerEl) timerEl.textContent = 'Kode sudah kedaluwarsa';
        }
        totalSeconds--;
    }
    const timerInterval = setInterval(updateTimer, 1000);
    updateTimer();

    // ---- Resend OTP ----
    if (resendBtn) {
        resendBtn.addEventListener('click', function() {
            this.disabled = true;
            this.textContent = 'Mengirim...';
            fetch('/web/resend-otp', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({jsonrpc: '2.0', method: 'call', params: {}}),
            })
            .then(r => r.json())
            .then(data => {
                if (data.result && data.result.success) {
                    totalSeconds = 5 * 60;
                    inputs.forEach(i => i.value = '');
                    inputs[0].focus();
                    // Update dev code if shown
                    const devEl = document.getElementById('devOtpCode');
                    if (devEl && data.result.code_dev) {
                        devEl.textContent = data.result.code_dev;
                    }
                }
                resendBtn.disabled = false;
                resendBtn.textContent = 'Kirim ulang kode';
            })
            .catch(() => {
                resendBtn.disabled = false;
                resendBtn.textContent = 'Kirim ulang kode';
            });
        });
    }

    // ---- Send to Email Button ----
    const sendEmailBtn = document.getElementById('sendToEmailBtn');
    const emailInput = document.getElementById('otpEmailInput');
    const emailStatus = document.getElementById('emailSendStatus');

    if (sendEmailBtn && emailInput) {
        sendEmailBtn.addEventListener('click', function() {
            const email = emailInput.value.trim();
            if (!email || !email.includes('@')) {
                if (emailStatus) {
                    emailStatus.textContent = 'Masukkan email yang valid';
                    emailStatus.className = 'tw-font-[\"Inter\"] tw-text-[12px] tw-mt-[8px] tw-m-0 tw-text-red-500';
                }
                return;
            }
            sendEmailBtn.disabled = true;
            sendEmailBtn.textContent = 'Mengirim...';

            fetch('/web/send-otp-email', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({jsonrpc: '2.0', method: 'call', params: {email: email}}),
            })
            .then(r => r.json())
            .then(data => {
                if (data.result && data.result.success) {
                    if (emailStatus) {
                        emailStatus.textContent = '✅ ' + data.result.message;
                        emailStatus.className = 'tw-font-[\"Inter\"] tw-text-[12px] tw-mt-[8px] tw-m-0 tw-text-green-600';
                    }
                    totalSeconds = 5 * 60;
                    inputs.forEach(i => i.value = '');
                    inputs[0].focus();
                } else {
                    if (emailStatus) {
                        emailStatus.textContent = '❌ ' + (data.result ? data.result.message : 'Error');
                        emailStatus.className = 'tw-font-[\"Inter\"] tw-text-[12px] tw-mt-[8px] tw-m-0 tw-text-red-500';
                    }
                }
                sendEmailBtn.disabled = false;
                sendEmailBtn.textContent = 'Kirim';
            })
            .catch(() => {
                sendEmailBtn.disabled = false;
                sendEmailBtn.textContent = 'Kirim';
            });
        });
    }
});
